import React, { useEffect, useState } from '@teact';
import type { FC } from '../../../lib/teact/teact';
import { memo } from '../../../lib/teact/teact';
import { withGlobal } from '../../../global';

import type { UserMemory } from '../../chatAssistant/type/types';

import { telegptSettings } from '../../chatAssistant/api/user-settings';
import { clearUserMemory, deleteUserMemory, getUserMemories } from '../../chatAssistant/utils/chat-api';

import useHistoryBack from '../../../hooks/useHistoryBack';

import Icon from '../../common/icons/Icon';
import Button from '../../ui/Button';
import Spinner from '../../ui/Spinner';
import Switcher from '../../ui/Switcher';

type OwnProps = {
  isActive?: boolean;
  onReset: () => void;
};

type StateProps = {
  currentUserId?: string;
};

const TelyAIMemoryContent: FC<OwnProps & StateProps> = ({
  isActive,
  onReset,
  currentUserId,
}) => {
  useHistoryBack({
    isActive,
    onBack: onReset,
  });
  const [memories, setMemories] = useState<UserMemory[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (!currentUserId) return;
    setIsLoading(true);
    getUserMemories(currentUserId).then((res) => {
      if (res.code === 0) {
        setMemories(res.data.memories);
      }
    }).finally(() => {
      setIsLoading(false);
    });
    telegptSettings.getGptSettings();
  }, [currentUserId]);

  const handleDeleteAll = () => {
    if (!currentUserId) return;
    clearUserMemory(currentUserId).then((res) => {
      if (res.code === 0) {
        setMemories([]);
      }
    });
  };

  const handleDeleteMemory = (memoryId: number) => {
    if (!currentUserId) return;
    deleteUserMemory(String(memoryId), currentUserId).then((res) => {
      if (res.code === 0) {
        setMemories((prev) => prev.filter((m) => m.id !== memoryId));
      }
    });
  };

  const handleMemorySaveChange = () => {
    telegptSettings.setSettingOption({ memory_enabled: !telegptSettings?.telegptSettings?.memory_enabled });
  };

  return (
    <div className="settings-content custom-scroll bg-[var(--color-background-secondary)] p-4">
      <div>
        <h4 className="settings-item-header">Memories</h4>
        <div className="p-[16px] rounded-[16px] bg-[var(--color-background)] flex justify-between items-center">
          <div>
            <div className="text-[1rem] font-semibold text-[var(--color-text)]">Reference Saved Memories</div>
            <div className="text-[0.75rem] text-[var(--color-text-secondary)]">When enabled, TelyAI will use your saved memories to provide personalized assistance.</div>
          </div>
          <Switcher label="Reference Saved Memories" checked={telegptSettings?.telegptSettings?.memory_enabled} onChange={handleMemorySaveChange} />
        </div>
      </div>
      <div>
        <div className="flex items-center justify-between my-2">
          <h4 className="settings-item-header mb-0">Manage Memories</h4>
          <Button
            noForcedUpperCase
            size="smaller"
            color="translucent"
            className="text-[14px] !py-[8px] !px-[12px] w-auto !text-[var(--color-primary)]"
            onClick={handleDeleteAll}
          >
            Delete All
          </Button>
        </div>
        <div className="flex flex-col gap-[12px]">
          {isLoading ? (
            <div className="flex justify-center items-center py-8">
              <Spinner />
            </div>
          ) : memories.length === 0 ? (
            <div className="flex justify-center items-center py-8">
              <div className="text-[1rem] text-[var(--color-text-secondary)]">No memory currently.</div>
            </div>
          ) : memories.map((memory) => (
            <div key={memory.id} className="p-[16px] rounded-[16px] bg-[var(--color-background)] flex justify-between items-center">
              <div>{memory.content}</div>
              <Button
                noForcedUpperCase
                size="smaller"
                color="translucent"
                round
                className="text-[14px] !py-[8px] !px-[12px] w-auto"
                onClick={() => handleDeleteMemory(memory.id)}
              >
                <Icon name="close" className="!text-[1rem]" />
              </Button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default memo(withGlobal<OwnProps>((global) => ({
  currentUserId: global.currentUserId,
}))(TelyAIMemoryContent));
