import React from '@teact';
/* eslint-disable max-len */
/* eslint-disable no-null/no-null */
/* eslint-disable @typescript-eslint/no-shadow */
import type { FC } from '../../../lib/teact/teact';
import { memo } from '../../../lib/teact/teact';

import Transition from '../../ui/Transition';
import TelyAIMemoryContent from './TelyAIMemoryContent';
import TelyAIMemoryHeader from './TelyAIMemoryHeader';

export type OwnProps = {
  onReset: (forceReturnToChatList?: true | Event) => void;
};

const TelyAIMemory: FC<OwnProps> = ({ onReset }) => {
  function renderCurrentSection() {
    return (
      <>
        <TelyAIMemoryHeader onReset={onReset} />
        <TelyAIMemoryContent onReset={onReset} />
      </>
    );
  }

  return (
    <Transition
      id="TelyAIMemory"
      name="fade"
      activeKey={0}
      renderCount={1}
      shouldWrap
      withSwipeControl
    >
      {renderCurrentSection}
    </Transition>
  );
};

export default memo(TelyAIMemory);
